class Solution:
  def solve(self, nums):
    if len(nums) <= 1:
      return True
    merged = [nums[0]]
    for num in nums[1:]:
      if num >= merged[-1]:
        merged.append(num)
      else:
        merged.append(merged.pop())
        merged.append(num)
    return merged == sorted(nums, reverse=True)

