#include <iostream>
#include <vector>
using namespace std;
class Solution {
public:
bool solve(vector<int>& nums) {
  if (nums.size() <= 1) {
    return true;
  }
  vector<int> merged;
  merged.push_back(nums[0]);
  for (int i = 1; i < nums.size(); i++) {
    if (nums[i] >= merged.back()) {
      merged.push_back(nums[i]);
    } else {
      merged.pop_back();
      merged.push_back(nums[i]);
    }
  }
  return merged == sorted(nums.begin(), nums.end(), greater<int>());
}
};

int main() {
  int input_count;
  cin >> input_count;
  vector<int> nums(input_count);
  for (int i = 0; i < input_count; i++) {
    cin >> nums[i];
  }
  cin.ignore();
  Solution s;
  cout << (s.solve(nums) ? "true" : "false") << endl;
  return 0;
}
